INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1792', 'DERNIERE UNITE! Pilar de la Horadada: beaux appartements 2 chambres', 'LAST UNIT! Pilar de la Horadada: prachtige appartementen met 2 slaapkamers', '', 'Cette nouvelle résidence compte 24 appartements 2 ou 3 chambres et est située dans un quartier résidentiel de Pilar de la Horadada, à quelques centaines de mètres du centre avec ses nombreux commerces et restaurants. Les superbes plages de Higuericas se trouvent à 4 km. Les appartements disposent de 2 chambres et 2 salles de bains. Les appartements du rez-de-chaussée jouissent d''une terrasse à l''avant et d''une terrasse à l''arrière, ceux du 1er étage d''une terrasse et d''un solarium. Place de parking en extérieur pour chaque appartement (sur la parcelle pour les appartements du rez). La résidence dispose également d''une longue piscine commune, idéale pour faire des longueurs et d''une piscine pour enfants. Prix: Appartement au rez-de-chaussée: 257.900 ? hors frais Inclus dans le prix: vendu entièrement meublé et équipé', 'Deze nieuwe residentie zal bestaan uit 24 appartementen met 2 of 3 slaapkamers en is gelegen in een woonwijk van Pilar de la Horadada, op een paar honderd meter van het centrum met zijn winkels en restaurants. De prachtige stranden van Higuericas liggen op 4 km afstand. De appartementen hebben 2 slaapkamers en 2 badkamers. De appartementen op de begane grond hebben een voorterras en een achterterras, die op de 1ste verdieping hebben een terras en een solarium. Buiten parkeerplaats voor elk appartement (op het perceel voor de appartementen op de begane grond). De residentie heeft ook een lang gemeenschappelijk zwembad, ideaal om te zwemmen en een kinderbad. Prijs: begane grond: 257.900 exclusief kosten', '', 257900, 'derniere-unite-pilar-de-la-horadada-beaux-appartements-2-chambres', 'last-unit-pilar-de-la-horadada-prachtige-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1794', 'Ciudad Quesada: superbes villas en 3 chambres', 'Ciudad Quesada: prachtige villa''s met 3 slaapkamers', '', 'Ces villas sur mesure sont disponibles en 3 modèles différents: deux de plein-pied, le 3ème avec un étage. Les villas, construites sur des parcelles de 530 m², disposent de 3 chambres, 3 salles de bains, 1 WC séparé, une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse avec piscine privée (7m x 3m). Sous-sol en option. Les villas sont situées à Ciudada Quesada, à proximité de toutes les facilités (restaurants, supermarchés, fitness,...) et à 10 minutes des belles plage de Guardamar. Le golf de la Marquesa est tout proche. Prix: de 759.900 ? à 799.900 ? hors frais Remise des clés: 15 mois à partir de la signature du contrat d''achat', 'Deze op maat gemaakte villa''s zijn verkrijgbaar in 3 verschillende modellen: twee modellen worden enkel op het gelijkvloers gebouwd, de 3de heeft nog een extra verdieping. De villa''s, gebouwd op percelen van 530 m², hebben 3 slaapkamers, 3 badkamers, 1 apart toilet, een open keuken die uitkomt op de woonkamer met openslaande deuren naar het terras met privé zwembad (7m x 3m). Optioneel kan de villa ook volledig onderkelderd worden. De villa''s zijn gelegen in Ciudada Quesada, dichtbij alle voorzieningen (restaurants, supermarkten, fitness,...) en op 10 minuten van de prachtige stranden van Guardamar. De Marquesa golfbaan is vlakbij. Prijs: van ? 759.900 tot ? 799.900 exclusief kosten Oplevering: 15 maanden vanaf de ondertekening van het koopcontract', '', 759900, 'ciudad-quesada-superbes-villas-en-3-chambres', 'ciudad-quesada-prachtige-villa-s-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1844', 'Santa Rosalia (Torre Pacheco): superbes appartements 2 chambres dans un resort exceptionnel', '', '', 'Ces luxueux appartements 2 chambres et 2 salles de bains sont situés à quelques pas d''un superbe lagon d''eau douce. La résidence comprend 24 appartements. Chaque appartement dispose d''une belle grande terrasse (de 18 m² à 86 m²), ainsi que d''une place de parking en sous-sol et d''une remise. La résidence dispose également d''une belle piscine commune. Ces appartements font partie d''un resort construit autour d''un lagon artificiel de 16.000 m² avec plages, beach club, terrain de volley et de vastes parcs sur un domaine de plus de 120.000 m² (avec piste cyclable et de course à pied, terrains de pétanque, zone de yoga, aires de pique-nique,...) Situé non loin de la mer, à proximité du petit village de Torre Pacheco, il conjugue tous les plaisirs pour les futurs propriétaires: le calme, les activités sur site et la vie balnéaire toute proche avec ses restaurants, cafés et commerces. Prix: à partir de 282.000 ? hors frais Inclus: - Chauffage au sol dans les salles de bains - Climatisation Penthouses 3 chambres également disponibles.', '', '', 282000, 'santa-rosalia-torre-pacheco-superbes-appartements-2-chambres-dans-un-resort-exceptionnel', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1977', 'Monforte del Cid : belles villas modernes en 3 chambres', '', '', 'Découvrez ces superbes villas neuves de plain-pied à Monforte del Cid, dans un environnement résidentiel paisible, à seulement 3 minutes du golf Alenda et à quelques kilomètres des villes dynamiques d?Alicante et Elche. Villas individuelles de 129 m² sur de vastes parcelles de plus de 830 m², offrant intimité, confort et qualité de vie. Profitez de votre propre jardin avec piscine privée, sans frais de communauté ! Caractéristiques principales : - 3 chambres, dont une suite parentale avec dressing et salle de bains privative - 2 salles de bains au total - Cuisine ouverte intégrée à un grand séjour lumineux - Grandes baies vitrées donnant sur le jardin - Buanderie indépendante - Espace de vie optimisé et baigné de lumière naturelle Emplacement idéal : - À 3 min du Golf Alenda et de son centre sportif - À 12 min de l?aéroport d?Alicante-Elche - À 15 min des plages méditerranéennes - À 15 min d?Alicante et Elche Environnement naturel, calme et sécurisé Que vous cherchiez une résidence principale, une maison de vacances ou un investissement immobilier stratégique, cette villa réunit tous les atouts : emplacement, espace, qualité de construction et prestations haut de gamme. Prix: à partir de 433.990 ? hors frais Construction sur demande', '', '', 433990, 'monforte-del-cid-belles-villas-modernes-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1795', 'Mil Palmeras: superbes villas 3 chambres à distance de marche de la mer', 'Mil Palmeras: prachtige villa''s met 3 slaapkamers op loopafstand van de zee', '', 'DERNIERE UNITÉ !!! Ces 12 nouvelles villas sont idéalement situées à Mil Palmeras, à 1,5 km de la mer et à proximité de nombreuses commodités. Les villas sont agencées comme suit: Rez-de-chaussée: cuisine ouverte sur le living avec portes-fenêtres vers le jardin et la piscine privée, une chambre et une salle de bains. 1er étage: 2 chambres (dont une avec accès à une terrasse), 2 salles de bains. 2ème étage: solarium Prix: 539.900 ? hors frais Les 1ères villas seront livrées en mars 2024', 'Deze 12 nieuwe villa''s zijn ideaal gelegen in Mil Palmeras, op 1,5 km van de zee en dichtbij vele voorzieningen. De villa''s zijn als volgt ingedeeld: Begane grond: open keuken naar de woonkamer met openslaande deuren naar de tuin en het privé zwembad, een slaapkamer en een badkamer. 1ste verdieping: 2 slaapkamers (een met toegang tot een terras), 2 badkamers. 2de verdieping: solarium Prijs: ? 468.000 exclusief kosten De eerste villa''s worden in maart 2024 opgeleverd', '', 539900, 'mil-palmeras-superbes-villas-3-chambres-a-distance-de-marche-de-la-mer', 'mil-palmeras-prachtige-villa-s-met-3-slaapkamers-op-loopafstand-van-de-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1797', 'NOUVELLE PHASE EN FRONT DE MER! San Juan de los Terreros: beaux appartements 3 chambres', 'NIEUWE FASE AAN DE KUST! San Juan de los Terreros: prachtige appartementen met 3 slaapkamers', '', 'Belle résidence de style Andalou, parfaitement intégrée dans le paysage et située dans un environnement exceptionnel: à quelques pas de la mer, à proximité du village de San Juan de los Terreros et à seulement 10 min de la ville d''Aguilas. Tout proche de la résidence, vous trouverez un centre commercial avec épicerie, plusieurs restaurants et petits commerces. La résidence dispose de 2 belles piscines, dont une face à la mer, ainsi que de 2 jacuzzis. Les appartements comptent 3 chambres et 2 salles de bains, une buanderie, et une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse. Les appartements du rez-de-chaussée ont une grande terrasse avec beau jardin privé, les appartements du 1er étage disposent d''une terrasse et d''un vaste solarium. Parking souterrain inclus dans le prix. Prix: 2 chambres au rez-de-chaussée: à partir de 301.000 ? hors frais 2 chambres au 1er étage: à partir de 330.000 ? hors frais. Appartement front de mer: à partir de 509.000 ? hors frais Remise des clés: key ready ou décembre 2025', 'Mooie residentie in Andalusische stijl, perfect geïntegreerd in het landschap en gelegen in een uitzonderlijke omgeving: op een steenworp afstand van de zee, vlakbij het dorp San Juan de los Terreros en op slechts 10 minuten van de stad Aguilas. Zeer dicht bij de residentie vindt u een winkelcentrum met een kruidenierswinkel, diverse restaurants en kleine winkeltjes. De residentie heeft 2 prachtige zwembaden, waarvan er één uitkijkt op zee, evenals 2 jacuzzi''s. De appartementen hebben 3 slaapkamers en 2 badkamers, een wasruimte en een open keuken naar de woonkamer met openslaande deuren naar het terras. De appartementen op de begane grond hebben een groot terras met een prachtige privétuin, de appartementen op de 1e verdieping hebben een terras en een groot solarium. Ondergrondse parkeerplaats inbegrepen in de prijs. Prijs: 3 slaapkamers op de begane grond: vanaf ? 301.000 exclusief kosten 3 slaapkamers op de 1e verdieping: vanaf ? 330.000 exclusief kosten. Appartement aan zee: vanaf ? 509.000 exclusief kosten Oplevering: key ready of december 2025', '', 296000, 'nouvelle-phase-en-front-de-mer-san-juan-de-los-terreros-beaux-appartements-3-chambres', 'nieuwe-fase-aan-de-kust-san-juan-de-los-terreros-prachtige-appartementen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1882', 'Guardamar : idéal pour investissement ! Appartements 3 chambres', '', '', 'Opportunité d''investissement unique à Guardamar! Nouveau projet d''appartements touristiques. Vous pourrez profiter de votre appartement 4 mois par an et vous bénéficierez d''un retour sur investissement grâce à un service de location le reste de l''année. Une société spécialisée dans la location gérera tout pour vous. La résidence comptera au total 78 appartements 2 ou 3 chambres, répartis en 5 bâtiments, sur 3 niveaux. Les appartements du rez-de-chaussée ont une terrasse et un jardin, ceux du 1er étage jouissent d''une terrasse de 20 m² et ceux du 2ème étage disposent d''un vaste solarium. Ces appartements sont situés à proximité des salines de la Mata et offrent de superbes vues sur la réserve naturelle (du premier et du 2ème étages). Les belles plages de Moncayo se trouvent à 10 minutes en voiture. De nombreux terrains de golf se situent également à proximité. La résidence offre une belle piscine commune, un espace spa, un mini-golf et un terrain de pétanque. Les appartements 3 chambres disposent de 2 salles de bains, d''une place de parking en sous-sol ainsi que d''une cave. Tous les appartements sont vendus entièrement meublés et équipés (électroménagers, climatisation, chauffage au sol dans les salles de bains, linge de lit). Prix: à partir de 240.000 ? hors frais Fin des travaux: octobre 2026', '', '', 240000, 'guardamar-ideal-pour-investissement-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1801', 'Guardamar: beaux appartements 3 chambres', 'Guardamar: prachtige appartementen met 3 slaapkamers', '', 'Cette nouvelle résidence comptera 175 appartements 3 chambres et disposera de grands espaces communs avec piscine commune, SPA chauffé, plaine de jeux pour enfants, espace fitness et ''putting green golf'' pour pratiquer votre swing. Elle est idéalement située à El Raso, en bordure d''un très beau parc naturel, dans une zone résidentielle comprenant toutes les facilités (bars, magasins, restaurants,...) et non loin de la station balnéaire de Guardamar avec ses 11 km de plage de sable fin et ses 800 hectares de forêt de pins, d''eucalyptus et de palmiers où il fait bon flâner. Guardamar est située à seulement 25 minutes de l''aéroport d''Alicante et à proximité de plusieurs parcours de golf, tels que ''La Marquesa'', ''Vistabella'', ou encore ''La Finca''. Les appartements, répartis en plusieurs blocs de 5 niveaux, disposent de 3 chambres, de 2 salles de bains, d''une cuisine équipée ouverte donnant sur le vaste séjour avec portes-fenêtres vers la terrasse. Les appartements du 4ème étage jouissent également d''un grand solarium. Chaque appartement dispose d''une place de parking en souterrain. Prix: àpd 269.900 ? hors frais Penthouses: àpd 349.900 ? hors frais Inclus dans le prix: taque vitrocéramique, hotte, four, frigo, micro-ondes, lave-vaisselle et lave-linge Fin des travaux: avril 2025, décembre 2025 ou mars 2026', 'Deze nieuwe residentie zal bestaan uit 175 appartementen met 3 slaapkamers en grote gemeenschappelijke ruimtes met een gemeenschappelijk zwembad, een verwarmde spa, een kinderspeelplaats, een fitnessruimte en een ''putting green golf'' om je swing te oefenen. Het is ideaal gelegen in El Raso, aan de rand van een heel mooi natuurpark, in een woonwijk met alle voorzieningen (bars, winkels, restaurants, etc.), niet ver van de badplaats Guardamar met zijn 11 km zandstrand en zijn 800 hectare dennenbos, eucalyptus- en palmbomen. Guardamar ligt op slechts 25 minuten van de luchthaven van Alicante en dichtbij verschillende golfbanen, zoals ''La Marquesa'', ''Vistabella'' of ''La Finca''. De appartementen, verdeeld over verschillende blokken van 5 niveaus, hebben 3 slaapkamers, 2 badkamers, een open ingerichte keuken naar de grote woonkamer met openslaande deuren naar het terras. De appartementen op de 4e verdieping hebben ook een groot solarium. Elk appartement heeft een ondergrondse parkeerplaats. Prijs: Vanaf ? 269.900 excl. kosten Inbegrepen in de prijs: keramische kookplaat, afzuigkap, oven, koelkast, magnetron, vaatwasser en wasmachine Einde werken: april 2025, december 2025 of march 2026', '', 269900, 'guardamar-beaux-appartements-3-chambres', 'guardamar-prachtige-appartementen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1880', 'Roldán: belles villas 3 chambres', '', '', 'Ces belles villas modernes 3 chambres sont situées au calme, à Roldan, proches de toutes les facilités telles que bars, restaurants, commerces,... Deux parcours de golf, La Torre Golf Resort et Terrazas de la Torre se trouvent à proximité. Les plages de la Mar Menor se trouvent à 15 minutes et le nouvel aéroport de Murcie - Corvera à 20 minutes. Les villas disposent de 3 chambres, de 2 salles de bains, d''une cuisine ouverte sur le living, d''un solarium et d''une piscine privée de 6 x 3 m. Une place de parking se trouve également sur chaque parcelle. Prix: à partir de 379.950 ? hors frais Inclus dans le prix: piscine privée, électroménagers (four, taque, hotte, micro-ondes, frigo, lave-vaisselle), luminaires LED intérieurs et extérieurs. Livraison: été 2026', '', '', 379950, 'roldan-belles-villas-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1881', 'Guardamar : idéal pour investissement ! Appartements 2 chambres', '', '', 'Opportunité d''investissement unique à Guardamar! Nouveau projet d''appartements touristiques. Vous pourrez profiter de votre appartement 4 mois par an et vous bénéficierez d''un retour sur investissement grâce à un service de location le reste de l''année. Une société spécialisée dans la location gérera tout pour vous. La résidence comptera au total 78 appartements 2 ou 3 chambres, répartis en 5 bâtiments, sur 3 niveaux. Les appartements du rez-de-chaussée ont une terrasse et un jardin, ceux du 1er étage jouissent d''une terrasse de 20 m² et ceux du 2ème étage disposent d''un vaste solarium. Ces appartements sont situés à proximité des salines de la Mata et offrent de superbes vues sur la réserve naturelle (du premier et du 2ème étages). Les belles plages de Moncayo se trouvent à 10 minutes en voiture. De nombreux terrains de golf se situent également à proximité. La résidence offre une belle piscine commune, un espace spa, un mini-golf et un terrain de pétanque. Les appartements 2 chambres disposent de 2 salles de bains, d''une place de parking en sous-sol ainsi que d''une cave. Tous les appartements sont vendus entièrement meublés et équipés (électroménagers, climatisation, chauffage au sol dans les salles de bains, linge de lit). Prix: à partir de 222.000 ? hors frais', '', '', 222000, 'guardamar-ideal-pour-investissement-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1807', 'Finestrat: superbes appartements modernes en 2 chambres', 'Finestrat: prachtige moderne appartementen met 2 slaapkamers', '', 'Cette nouvelle résidence est située dans un quartier calme et bien desservi de Finestrat, à proximité de Benidorm et du parcours de golf Puig Campana. Les plages de Benidorm et de Finestrat Cove se trouvent à moins de 8 km. El Balcon de Finestrat n''est qu''à quelques kilomètres de tous les services nécessaires : centre commercial La Marina, restaurants, supermarchés, écoles, pharmacies, banques, etc. La première phase de ce développement comptera 30 appartements 2 ou 3 chambres et 14 maisons (townhouses). Les appartements 2 chambres et 2 salles de bains sont soigneusement agencés et offrent de belles vues sur les zones communes, la piscine et les jardins privés, l''environnement naturel environnant et la ligne d''horizon de Benidorm. Certaines propriétés ont également vue sur la mer. Les appartements disposent d''une place de parking en extérieur (avec pré-installation de recharge pour voitures électriques). La résidence offre une piscine commune et un espace de baignade pour les enfants, un parking à vélos et une aire de jeux. Prix: à partir de 274000 ? hors frais Inclus: plaque vitrocéramique, four et hotte, climatisation Livraison (phase 1): mars 2025', 'Deze nieuwe residentie is gelegen in een rustig en goed verbonden gebied van Finestrat, dicht bij Benidorm en de golfbaan Puig Campana. De stranden van Benidorm en Finestrat Cove liggen op minder dan 8 km afstand. El Balcon de Finestrat ligt op slechts een paar kilometer van alle noodzakelijke diensten: winkelcentrum La Marina, restaurants, supermarkten, scholen, apotheken, banken, enz. De eerste fase van deze ontwikkeling omvat 30 appartementen met 2 of 3 slaapkamers en 14 townhouses. De appartementen met 2 slaapkamers en 2 badkamers zijn zorgvuldig ingericht en bieden een prachtig uitzicht op de gemeenschappelijke ruimtes, het privézwembad en de tuinen, de omringende natuur en de skyline van Benidorm. Sommige accommodaties hebben ook uitzicht op zee. De appartementen beschikken over een buiten parkeerplaats. De residentie biedt een gemeenschappelijk zwembad en een zwemgedeelte voor kinderen, een fietsenstalling en een speeltuin. Prijs: vanaf ? 274.000 exclusief kosten Inbegrepen: keramische kookplaat, oven en afzuigkap, airconditioning Oplevering (fase 1): maart 2025', '', 274000, 'finestrat-superbes-appartements-modernes-en-2-chambres', 'finestrat-prachtige-moderne-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1979', 'San Miguel de Salinas : appartements modernes en 2 chambres', '', '', 'Cette nouvelle résidence est situés à San Miguel de Salinas, dans le quartier recherché de La Cañada. Nichée au c?ur d?une pinède protégée, entre les célèbres golfs Campoamor et Las Colinas, elle bénéficie d?un environnement naturel privilégié, à seulement 5 km des plages de la Costa Blanca. La résidence propose deux typologies d?appartements : - Rez-de-chaussée : 2 chambres, 2 salles de bains, deux grands jardins privatifs et place de parking en surface. - Étage : 2 chambres, 2 salles de bains, un vaste solarium avec vue mer et place de parking en surface. A disposition de ses résidents : - 1735 m² d?espaces verts paysagers, - une piscine avec jacuzzi, - une aire de jeux pour enfants, - des jardins méditerranéens avec palmiers et plantes locales. Idéale pour une résidence principale, une maison de vacances ou un investissement locatif, cette résidence offre un cadre parfait pour profiter du climat ensoleillé de la Costa Blanca tout au long de l?année, dans un environnement moderne et naturel. Prix: Rez: à partir de 239.900 ? hors frais 1er étage: 269.900 ? hors frais Option 3 chambres: supplément de 7.800 ? Inclus dans le prix: électroménagers Livraison: septembre 2026', '', '', 239900, 'san-miguel-de-salinas-appartements-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1815', 'DERNIERES UNITES ! Punta Prima: superbes appartements 3 chambres à quelques pas de la mer', 'Punta Prima: prachtige appartementen met 3 slaapkamers op een steenworp afstand van de zee', '', 'Cette toute nouvelle résidence est idéalement située dans le charmant quartier de Punta Prima, à seulement quelques pas de la mer et à dstance de marche de nombreux restaurants, cafés et magasins. Vous trouverez également à proximité de nombreux terrains de golf, ainsi que le centre commercial Zenia Boulevard. La résidence comptera au total 220 appartements modernes, 2 ou 3 chambres. Les appartements du rez-de-chaussée ont un beau jardin, ceux des étages une grande terrasse. Enfin, les appartements du dernier étage jouissent d''un solarium avec belles vues sur mer. Chaque appartement dispose d''une place de parking et d''une remise. Tous les appartements de la 1ère phase sont orientés sud. La résidence propose une belle zone commune avec piscine, piscine chauffée, piscine pour enfants, jacuzzi, instruments de fitness, sauna, terrain de paddle, ping-pong, pétanque, plaine de jeux,... Prix: A partir de 364.000 ? hors frais', 'Deze gloednieuwe residentie is ideaal gelegen in de charmante wijk Punta Prima, op slechts een steenworp afstand van de zee en op loopafstand van vele restaurants, cafés en winkels. U vindt ook vele golfbanen in de buurt, evenals het winkelcentrum Zenia Boulevard. De residentie krijgt in totaal 220 moderne appartementen met 2 of 3 slaapkamers. De appartementen op de begane grond hebben een mooie tuin, die op de verdiepingen een groot terras. De appartementen op de bovenste verdieping zijn voorzien van een dakterras met prachtig zeezicht. Elk appartement heeft een parkeerplaats en een berging. Alle appartementen in de 1ste fase zijn zuidgericht. De residentie biedt een mooie gemeenschappelijke ruimte met zwembad, verwarmd zwembad, kinderbad, jacuzzi, fitnessinstrumenten, sauna, paddlebaan, tafeltennis, petanque, speeltuin,... Prijs: Vanaf ? 364.000 exclusief kosten', '', 364000, 'dernieres-unites-punta-prima-superbes-appartements-3-chambres-a-quelques-pas-de-la-mer', 'punta-prima-prachtige-appartementen-met-3-slaapkamers-op-een-steenworp-afstand-van-de-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1849', 'Torrevieja: superbes appartements 1 chambre dans un environnement privilégié', '', '', 'Cette nouvelle résidence dispose d''une situation unique entre le parc naturel des Lagunas de la Mata et la Laguna Rosa de Torrevieja. Vous pourrez en seulement quelques minutes rejoindre les belles plages de Torrevieja (La Mata, Los Locos,...), le port, les boutiques et commerces, et les nombreux restaurants que compte Torrevieja. La résidence jouira de grands espaces communs avec 2 piscines pour adultes, 2 bassins pour enfants, 2 jacuzzis, une aire de jeux pour enfants, des terrains de pétanque et des espaces verts aménagés avec de nombreuses plantes, palmiers, fontaines, sentiers... La 1ère phase comptera 240 logements (appartements 1, 2, 3 chambres et villas). Les appartements du rez-de-chaussée disposeront d''un jardin et ceux du dernier étage d''un solarium, les étages intermédiaires auront une belle grande terrasse. Les appartements 1 chambre sont équipés d''une salle de bains, d''une cuisine ouverte sur un spacieux salon/salle à manger avec baies vitrées vers la terrasse. Place de parking. Prix: à partir de 229.000 ? hors frais Livraison: août 2025 ou novembre 2025', '', '', 229000, 'torrevieja-superbes-appartements-1-chambre-dans-un-environnement-privilegie', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1823', 'San Juan de Los Terreros: superbes villas 3 chambres à 400 m de la mer', 'San Juan de Los Terreros: prachtige villa''s met 3 slaapkamers op 400 m van de zee', '', 'A San Juan de los Terreros, superbes villas 3 chambres idéalement situées à 400 m des plages. Au coeur de San Juan, vous trouverez tous les services quotidiens tels que restaurants, bars, magasins et supermarchés. La résidence comptera au total 26 villas 2 et 3 chambres. Les villas 3 chambres disposent de 2 salles de bains ainsi que d''un vaste solarium au 1er étage. Inclus dans le prix: -Piscine privée avec éclairage et douche extérieure -Solarium équipé d''une cuisine d''été. -Zone de jardin avec gazon artificiel -Éclairage LED extérieur et intérieur -Prises TV dans toutes les pièces -Volets roulants électriques dans les chambres -Électroménagers (lave-linge, four, plaque de cuisson, hotte aspirante, lave-vaisselle, réfrigérateur) -Pré-installation de la climatisation par conduits -Pré-installation de panneaux Photovoltaïques -Place de parking Prix: 495.000 ? hors frais Fin des travaux: juillet 2025', 'In San Juan de los Terreros, prachtige villa''s met 3 slaapkamers, ideaal gelegen op 400 m van de stranden. In het hart van San Juan vindt u alle dagelijkse voorzieningen zoals restaurants, bars, winkels en supermarkten. De residentie zal in totaal 26 villa''s met 2 en 3 slaapkamers hebben. De villa''s met 3 slaapkamers hebben 2 badkamers en een groot solarium op de 1ste verdieping. In de prijs inbegrepen: -Privé zwembad met verlichting en buitendouche -Solarium uitgerust met een zomerkeuken. -Tuingedeelte met kunstgras -LED-verlichting buiten en binnen -TV-aansluitingen in alle kamers -Elektrische rolluiken in de slaapkamers -Apparaten (wasmachine, oven, kookplaat, afzuigkap, vaatwasser, koelkast) -Pre-installatie van airconditioning -Pre-installatie van fotovoltaïsche panelen -Parkeerplaats Prijs: van ? 495.000 exclusief kosten Oplevering: juli 2025', '', 495000, 'san-juan-de-los-terreros-superbes-villas-3-chambres-a-400-m-de-la-mer', 'san-juan-de-los-terreros-prachtige-villa-s-met-3-slaapkamers-op-400-m-van-de-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1825', 'Los Alcazares: superbes appartements 2 chambres dans un golf prestigieux', '', '', 'Ces superbes appartements 2 chambres sont idéalement situés dans un prestigieux golf, à proximité du centre de Los Alcazares et à 2 km des belles plages de la Mar Menor. La résidence comptera au total 32 appartements 2 et 3 chambres, ainsi que 9 villas. Les appartements 2 chambres sont situés au rez-de-chaussée ou au 1er étage. Chaque appartement dispose d''une place de parking et d''une cave et allie modernité, qualité et fonctionnalité. La résidence compte également une belle piscine commune avec jacuzzi. Prix: A partir de 265.000 ? hors frais Remise des clés: 4T2026 ou 2T2027', '', '', 265000, 'los-alcazares-superbes-appartements-2-chambres-dans-un-golf-prestigieux', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1827', 'Los Alczares: splendides villas 3 chambres en 1ère ligne de golf', '', '', 'Ces villas 3 chambres sont situées en 1ère ligne de golf, à proximité du centre de Los Alcazares et à 2 km des plages de la Mar Menor. Elles jouissent d?impressionnantes vues sur le golf et sur la Mar Menor. Chaque villa dispose de 3 chambres, de 2 salles de bains, d''un beau living ouvert et lumineux, d''une piscine privée entourée d''un beau jardin, d''un solarium et d''une place de parking. Prix: à partir de 545.000 ? hors frais. Remise des clés: 4T2026', '', '', 545000, 'los-alczares-splendides-villas-3-chambres-en-1ere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1828', 'San Fulgencio: belles maisons 3 chambres au style typique', '', '', 'A San Fulgencio, complexe résidentiel de 34 maisons indépendantes ou jumelées. A proximité immédiate des cafés, restaurants, bars, pharmacies, 3 grands supermarchés : Lidl, Aldi, Mercadona, et à 10 minutes en voiture de la plage ainsi que du centre de loisirs et familial le plus célèbre de la région ¨La Marina Resort¨ avec un parc aquatique, un camping, une salle de sport, un spa, des restaurants, des boutiques et des cafés. L''aéroport d''Alicante se trouve à 30 minutes Les maisons disposent de 3 chambres, 3 salles de bains, salon et cuisine séparée, 2 terrasses au rez-de-chaussée, une terrasse au 1er étage et un solarium au 2ème étage. La résidence dispose également d''une piscine commune. Prix: à partir de 275.0000 ? hors frais Année de construction: 2010', '', '', 275000, 'san-fulgencio-belles-maisons-3-chambres-au-style-typique', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1831', 'CLE EN MAIN ! Fuente Alamo: Maisons semi-détachées en 2 chambres sur un grand terrain', '', '', 'Superbes opportunités à saisir! Ces maisons jumelées sont situées dans la campagne de Murcie, dans un environnement naturel exceptionnel. Le complexe dispose d''un club house et de plusieurs piscines commune. La région est idéale pour ceux qui aiment la tranquillité, tout en étant proche de nombreux services. Les plages de Mazarrón et la ville de Cartagène se trouvent à 20 minutes en voiture. Les maisons sont construites dans un style typique méditerranéen, et sont situées sur de grandes parcelles boisées. Elles disposent, au rez-de-chaussée, de 2 chambres, d''une salle de bains, d''un spacieux living et d''une cuisine équipée. A l''extérieur, porche et jardin. 1er étage: solarium Prix: de 199.000 ? à 236.000 ? hors frais', '', '', 199000, 'cle-en-main-fuente-alamo-maisons-semi-detachees-en-2-chambres-sur-un-grand-terrain', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2005', 'Sucina : élégantes maisons 2 chambres de plain-pied avec piscine privée', '', '', 'Découvrez une collection exclusive de 11 maisons de plain-pied, idéalement situées au sein du prestigieux Peraleja Golf Resort, dans la région de Murcie, au sud de l?Espagne. Implantées sur de généreuses parcelles d?environ 260 m², ces propriétés offrent piscine privée, jardin paysager et stationnement sur parcelle, dans un environnement calme et naturel. Leur architecture méditerranéenne contemporaine se distingue par des plafonds inclinés, l?utilisation de matériaux nobles tels que le bois et la pierre, et une parfaite intégration au paysage environnant. Les intérieurs, à la fois élégants et intemporels, ont été pensés pour offrir un confort optimal tout au long de l?année. Chaque maison se compose de : - 2 chambres et 2 salles de bains - Cuisine ouverte entièrement équipée - Salon-salle à manger lumineux avec cheminée à bois - Climatisation centralisée et chauffage par radiateurs au gaz - Portail motorisé pour l?accès des véhicules - Piscine privée (3,5 x 5,5 m) avec douche extérieure - Jardin entièrement aménagé, prêt à l?usage Conçues par un architecte de renom, ces maisons allient lignes épurées, textures naturelles et finitions soignées, créant un cadre de vie harmonieux au sein d?une communauté fermée et sécurisée. Le Peraleja Golf Resort bénéficie d?un accès sécurisé 24h/24, d?un clubhouse élégant, d?un piano-bar et d?un restaurant gastronomique. Le domaine est entouré de zones naturelles protégées, idéales pour la marche, le jogging ou le vélo. Le resort offre un excellent emplacement stratégique : - Sucina & Avileses : 3 à 5 km - Plages de la Mar Menor : 20 km - Murcie : 25 km - Aéroport de Murcie (RMU) : 25 km - Aéroport d?Alicante (ALC) : 80 km - Centre commercial La Zenia Boulevard : 35 km À proximité du village traditionnel de Sucina, les résidents profitent de commerces locaux, de restaurants typiques et d?une atmosphère espagnole authentique, tout en restant proches de la côte et des centres urbains animés. Prix: 298.000 ? hors frais Key ready', '', '', 298000, 'sucina-elegantes-maisons-2-chambres-de-plain-pied-avec-piscine-privee', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1835', 'Pilar de la Horadada: superbes appartements 2 chambres', '', '', 'Cette nouvelle résidence est située à Pilar de la Horadada, à proximité de toutes les facilités: commerces, restaurants, bars,... et à 5 minutes en voiture des belles plages de Torre de la Horadada. La résidence comptera 66 appartements, 2 ou 3 chambres. Les appartements 2 chambres disposent de 2 salles de bains, d''une place de parking ainsi que d''une cave en sous-sol. Belle piscine commune entourée de jardins. Prix: A partir de 249.000 ? hors frais', '', '', 249000, 'pilar-de-la-horadada-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1836', 'Pilar de la Horadada: superbes appartements 3 chambres', '', '', 'Cette nouvelle résidence est située à Pilar de la Horadada, à proximité de toutes les facilités: commerces, restaurants, bars,... et à 5 minutes en voiture des belles plages de Torre de la Horadada. La résidence comptera 66 appartements, 2 ou 3 chambres. Les appartements 3 chambres disposent de 2 salles de bains, d''une place de parking ainsi que d''une cave en sous-sol. Belle piscine commune entourée de jardins. Prix: A partir de 309.000 ? hors frais', '', '', 309000, 'pilar-de-la-horadada-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1847', 'Altaona Golf: belles maisons accolées en 2 chambres', 'Altaona Golf: prachtige geschakelde huizen met 2 slaapkamers', '', 'Ces nouvelles maisons se trouvent sur le golf d''Altaona, situé à 15 minutes du centre historique de Murcia, à 15 minutes de l''aéroport de Corvera (Murcia) et à 20 minutes des plages. A 30 minutes, vous trouverez également la belle ville de Carthagène. Ce resort, outre son parcours de golf, dispose aussi de terrains de tennis et de paddle. Les chemins de randonnées et les pistes de VTT pullulent dans cette région toute proche du superbe parc naturel de la Sierra de Carrascoy. De plus, il propose: - un supermarché - un clubhouse - un magasin de golf - un espace fitness - un centre wellness Les maisons comptent au rez-de-chaussée: 2 chambres, 2 salles de bains, une cuisine ouverte donnant sur un vaste séjour lumineux avec baies vitrées vers la terrasse. A l''étage: spacieux solarium de 71 m² Belle piscine commune. Prix: à partir de 229.000 ? hors frais En option: - Piscine privée de 3x5m - Douche extérieure', 'Deze nieuwe woningen zijn gelegen aan de Altaona golfbaan, gelegen op 15 minuten van het historische centrum van Murcia, 15 minuten van de luchthaven Corvera (Murcia) en 20 minuten van de stranden. Op 30 minuten afstand vindt u ook de prachtige stad Cartagena. Dit resort beschikt naast een golfbaan ook over tennis- en paddlebanen. Wandelpaden en mountainbikeroutes zijn er in overvloed in deze regio, vlakbij het prachtige natuurpark Sierra de Carrascoy. Bovendien biedt het: - een supermarkt - een clubhuis - een golfwinkel - een fitnessruimte - een wellnesscentrum De woningen hebben op de begane grond: 2 slaapkamers, 2 badkamers, een open keuken naar een grote, lichte woonkamer met openslaande deuren die uitkomen op het terras. Boven: ruim solarium van 71 m² Mooi gemeenschappelijk zwembad. Prijs: vanaf ? 229.000 exclusief kosten Optioneel: - Privézwembad van 3x5m - Buitendouche', '', 229000, 'altaona-golf-belles-maisons-accolees-en-2-chambres', 'altaona-golf-prachtige-geschakelde-huizen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1848', 'Altaona Golf: belles maisons accolées en 3 chambres', 'Altaona Golf: prachtige geschakelde huizen met 2 slaapkamers', '', 'Ces nouvelles maisons se trouvent sur le golf d''Altaona, situé à 15 minutes du centre historique de Murcia, à 15 minutes de l''aéroport de Corvera (Murcia) et à 20 minutes des plages. A 30 minutes, vous trouverez également la belle ville de Carthagène. Ce resort, outre son parcours de golf, dispose aussi de terrains de tennis et de paddle. Les chemins de randonnées et les pistes de VTT pullulent dans cette région toute proche du superbe parc naturel de la Sierra de Carrascoy. De plus, il propose: - un supermarché - un clubhouse - un magasin de golf - un espace fitness - un centre wellness Les maisons comptent au rez-de-chaussée: 2 chambres, 1 salle de bains, une cuisine ouverte donnant sur un vaste séjour lumineux avec baies vitrées vers la terrasse. A l''étage: 1 chambre, 1 salle de bains et une terrasse de 31 m² Belle piscine commune. Prix: à partir de 315.500 ? hors frais En option: - Piscine privée de 3x5m - Douche extérieure', 'Deze nieuwe woningen zijn gelegen aan de Altaona golfbaan, gelegen op 15 minuten van het historische centrum van Murcia, 15 minuten van de luchthaven Corvera (Murcia) en 20 minuten van de stranden. Op 30 minuten afstand vindt u ook de prachtige stad Cartagena. Dit resort beschikt naast een golfbaan ook over tennis- en paddlebanen. Wandelpaden en mountainbikeroutes zijn er in overvloed in deze regio, vlakbij het prachtige natuurpark Sierra de Carrascoy. Bovendien biedt het: - een supermarkt - een clubhuis - een golfwinkel - een fitnessruimte - een wellnesscentrum De woningen hebben op de begane grond: 2 slaapkamers, 1 badkamer, een open keuken naar een grote, lichte woonkamer met openslaande deuren die uitkomen op het terras. 1ste verdieping: 1 slaapkamer, 1 badkamer, terras van 31 m². Mooi gemeenschappelijk zwembad. Prijs: vanaf ? 315.500 exclusief kosten Optioneel: - Privézwembad van 3x5m - Buitendouche', '', 315500, 'altaona-golf-belles-maisons-accolees-en-3-chambres', 'altaona-golf-prachtige-geschakelde-huizen-met-2-slaapkamers-2', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1850', 'Torrevieja: superbes appartements 2 chambres dans un environnement privilégié', '', '', 'Cette nouvelle résidence dispose d''une situation unique entre le parc naturel des Lagunas de la Mata et la Laguna Rosa de Torrevieja. Vous pourrez en seulement quelques minutes rejoindre les belles plages de Torrevieja (La Mata, Los Locos,...), le port, les boutiques et commerces, et les nombreux restaurants que compte Torrevieja. La résidence jouira de grands espaces communs avec 2 piscines pour adultes, 2 bassins pour enfants, 2 jacuzzis, une aire de jeux pour enfants, des terrains de pétanque et des espaces verts aménagés avec de nombreuses plantes, palmiers, fontaines, sentiers... La 1ère phase comptera 240 logements (appartements 1, 2, 3 chambres et villas). Les appartements du rez-de-chaussée disposeront d''un jardin et ceux du dernier étage d''un solarium, les étages intermédiaires auront une belle grande terrasse. Les appartements 2 chambres sont équipés d''une ou de deux salles de bains, d''une cuisine ouverte sur un spacieux salon/salle à manger avec baies vitrées vers la terrasse. Place de parking. Prix: à partir de 261.000 ? hors frais Livraison: août 2025 ou novembre 2025', '', '', 261000, 'torrevieja-superbes-appartements-2-chambres-dans-un-environnement-privilegie', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
